#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 100005
#define MAX_Q 100005
#define MAX_K 300005

int T, N, Q, k;
int a[MAX_N];
int u[MAX_K];
int r;
int ans;

// Function to find the minimum absolute difference
int find_min_diff(int r, int *u, int k) {
    int min_diff = INT_MAX;
    for (int i = 0; i < k; i++) {
        int diff = abs(a[u[i]] - r);
        if (diff < min_diff) {
            min_diff = diff;
        }
    }
    return min_diff;
}

int main() {
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &Q);
        for (int i = 1; i <= N; i++) {
            scanf("%d", &a[i]);
        }
        // Read the tree edges
        for (int i = 1; i < N; i++) {
            int x, y;
            scanf("%d %d", &x, &y);
            // Add edge to the tree
        }
        for (int i = 0; i < Q; i++) {
            scanf("%d %d", &r, &k);
            for (int j = 0; j < k; j++) {
                scanf("%d", &u[j]);
            }
            // XOR the values
            for (int j = 0; j < k; j++) {
                u[j] ^= ans;
            }
            r ^= ans;
            ans = find_min_diff(r, u, k);
            printf("%d\n", ans);
        }
    }
    return 0;
}

