import java.util.Scanner;
public class Main {
    static final int MAX_N = 100005;
    static final int MAX_Q = 100005;
    static final int MAX_K = 300005;
    static int T, N, Q, k;
    static int[] a = new int[MAX_N];
    static int[] u = new int[MAX_K];
    static int r;
    static int ans;

    // Function to find the minimum absolute difference
    static int find_min_diff(int r, int[] u, int k) {
        int min_diff = Integer.MAX_VALUE;
        for (int i = 0; i < k; i++) {
            int diff = Math.abs(a[u[i]] - r);
            if (diff < min_diff) {
                min_diff = diff;
            }
        }
        return min_diff;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        T = sc.nextInt();
        while (T-- > 0) {
            N = sc.nextInt();
            Q = sc.nextInt();
            for (int i = 1; i <= N; i++) {
                a[i] = sc.nextInt();
            }
            // Read the tree edges
            for (int i = 1; i < N; i++) {
                int x = sc.nextInt();
                int y = sc.nextInt();
                // Add edge to the tree
            }
            for (int i = 0; i < Q; i++) {
                r = sc.nextInt();
                k = sc.nextInt();
                for (int j = 0; j < k; j++) {
                    u[j] = sc.nextInt();
                }
                // XOR the values
                for (int j = 0; j < k; j++) {
                    u[j] ^= ans;
                }
                r ^= ans;
                ans = find_min_diff(r, u, k);
                System.out.println(ans);
            }
        }
    }
}

